<template>
  <div class="home">
    <!-- 3. 使用组件 -->
    <SideMenu class="home-left" :storageValue="storageValue"></SideMenu>
    <!-- 右侧内容区 -->
    <div class="home-right">
      <div class="operation-wrapper">
        <OperationMenu :fileType="fileType"
                       :filePath="filePath"
                       @getTableData="getFileData"
                       @handleUploadFile="handleUploadFile"
                       :operationFileList="operationFileList"
                       @handleSelectFile="setOperationFile"
                       @handleMoveFile="setMoveFileDialog"
        ></OperationMenu>
      </div>
      <!-- 面包屑导航栏 - 显示文件路径 -->
      <BreadCrumb :fileType="fileType"></BreadCrumb>
      <FileTable :tableData="tableData" @getTableData="getFileData" :loading="loading"></FileTable>
      <FileUploader ref="globalUploader" @getTableData="getFileData"></FileUploader>
      <FilePagination
          :pageData="pageData"
          @changePageData="changePageData"
      ></FilePagination>
    </div>
  </div>
</template>

<script>
import SideMenu from "@/views/Home/components/SideMenu";
import BreadCrumb from "@/views/Home/components/BreadCrumb";
import FileTable from "@/views/Home/components/FileTable";
import FilePagination from "@/views/Home/components/FilePagination";
import {getFileListByPath, getFileListByType} from "@/request/file";
import OperationMenu from '@/views/Home/components/OperationMenu'
import FileUploader from '@/views/Home/components/FileUploader'
import {getFileStorage} from '@/request/file.js' //  1.引入接口

export default {
  name: "Home",
  data() {
    return {
      storageValue: 0, //  存储空间占用大小
      tableData: [],
      loading: false,
      pageData: {
        currentPage: 1,
        pageCount: 20,
        total: 0,
      },
    };
  },
  components: {
    SideMenu,
    BreadCrumb,
    FileTable,
    FilePagination,
    OperationMenu,
    FileUploader,
  },
  computed: {
    // 左侧菜单选中的文件类型
    fileType() {
      return this.$route.query.fileType
          ? Number(this.$route.query.fileType)
          : 0;
    },
    filePath() {
      return this.$route.query.filePath ? this.$route.query.filePath : '/';
    }
  },
  watch: {
    filePath() {
      if (this.fileType === 0) {
        this.getFileData();
      }
    },
    fileType() {
      this.getFileData();
    },
  },
  mounted(){
    this.getFileData();
  },
  methods: {
    // 获取文件列表
    getFileData() {
      this.loading = true; // 打开表格loading状态
      if (this.fileType === 0) {
        // 左侧菜单选择的为 全部 时，根据路径，获取文件列表
        this.loading = false;
        this.getFileDataByPath();
      } else {
        // 左侧菜单选择的为 除全部以外 的类型时，根据类型，获取文件列表
        this.getFileDataByType();
      }
      this.getStorageValue() //  2.调用获取文件占用空间函数
    },
    // 获取文件占用空间
    getStorageValue() {
      getFileStorage().then((res) => {
        //    3. 调用接口
        if (res.success) {
          this.storageValue = res.data ? res.data : 0 //    4.赋值
        } else {
          this.$message.error(res.message)
        }
      })
    },
    handleUploadFile() {
      this.$refs.globalUploader.triggerSelectFileClick()
    },
    // 根据路径获取文件列表
    getFileDataByPath() {
      getFileListByPath({
        filePath: this.filePath,
        currentPage: this.pageData.currentPage,
        pageCount: this.pageData.pageCount,
      }).then(
          (res) => {
            this.loading = false; //  关闭表格loading状态
            if (res.success) {
              this.tableData = res.data.list; // 表格数据赋值
              this.pageData.total = res.data.total; //  分页组件 - 文件总数赋值
            } else {
              this.$message.error(res.message);
            }
          },
          (error) => {
            this.loading = false;
            console.log(error);
          }
      );
    },
    // 根据类型获取文件列表
    getFileDataByType() {
      getFileListByType({
        fileType: this.fileType, //  文件类型
        currentPage: this.pageData.currentPage, //  当前页码
        pageCount: this.pageData.pageCount, //  每页条目数
      }).then(
          (res) => {
            this.loading = false; //  关闭表格loading状态
            if (res.success) {
              this.tableData = res.data.list; // 表格数据赋值
              this.pageData.total = res.data.total; //  分页组件 - 文件总数赋值
            } else {
              this.$message.error(res.message);
            }
          },
          (error) => {
            this.loading = false;
            console.log(error);
          }
      );
    },
    // 分页组件 - 页码或当页条目数改变时
    changePageData(pageData) {
      this.pageData.currentPage = pageData.currentPage; // 页码赋值
      this.pageData.pageCount = pageData.pageCount; //  每页条目数赋值
      this.getFileData(); // 获取文件列表
    },
  },
};
</script>

<style lang="stylus" scoped>
.home {
  display: flex;

  .home-left {
    box-sizing: border-box;
  }

  .home-right {
    box-sizing: border-box;
    width: calc(100% - 200px);
    padding: 8px 24px;
    flex: 1;

    .operation-wrapper {
      margin-bottom: 16px;
      display: flex;
      align-items: center;
      justify-content: space-between;
    }
  }
}
</style>