import axios from "axios"
import {Message} from "element-ui"
import Cookies from "js-cookie"

//设置超时时间
axios.defaults.timeout = 10000 * 5;

//请求基础URL
axios.defaults.baseURL = "http://117.50.179.8:18088";

//自定义post请求头
axios.defaults.headers.post["Content-Type"] = "application /x-www-form-urlencoded";

//请求拦截
axios.interceptors.request.use(
    (config) => {
        config.headers["token"] = Cookies.get("token");
        return config;
    },
    (error) => {
        console.log(error);
        return Promise.reject(error);
    }
);

//响应拦截
axios.interceptors.response.use(
    (response) => {
        if(response.status == 200){
            return Promise.resolve(response)
        }
    },
    (error) => {
        if(error.response.status){
            switch (error.response.status){
                case 500:
                    Message.error("后台服务发生错误");
                    break;
                case 401:
                    Message.error("无权限");
                    break;
                case 404:
                    Message.error("当前接口不存在");
                    break;
                default:
                    this.$message.error(error.response.message);
                    return Promise.reject(error.response);
            }
        }
    }
);

/**
 * get方法,对应get请求
 * @param url
 * @param params
 * @param info
 */
export function get(url, params, info=""){
    return new Promise((resolve, reject) => {
        axios.get(url + info, {
            params: params
        }).then(
            (res) => {
                resolve(res.data);
            }
        ).catch((err) => {
            reject(err.data);
        })
    })
}

/**
 * post方法，对应post请求
 * info为 true，formData格式
 * nfo为 undefined或false，是json格式
 * @param url
 * @param data
 * @param info
 */
export function post(url, data = {}, info){
    return new Promise((resolve, reject) => {
        let newData = data;
        if(info){
            newData = new FormData();
            for(let i in data){
                newData.append(i,data[i]);
            }
        }
        axios.post(url, newData).then(
            (res) => {
                resolve(res.data);
            }
        ).catch(
            (err) => {
                reject(err.data);
            }
        )
    })
}

/**
 * put请求
 * @param url
 * @param params
 * @param info
 * @returns {Promise<unknown>}
 */
export function put(url, params = {}, info = ""){
    return new Promise((resolve, reject) => {
        axios.put(url + info, params).then(
            (res) => {
                resolve(res.data);
            },
            (err) => {
                reject(err.data);
            }
        );
    });
}

/**
 * delete
 * @param url
 * @param params
 * @param info
 * @returns {Promise<unknown>}
 */
export function dele(url, params = {}, info = "") {
    return new Promise((resolve, reject) => {
        axios
            .delete(url + info, {
                params: params,
            })
            .then((res) => {
                resolve(res.data);
            })
            .catch((err) => {
                reject(err.data);
            });
    });
}