<template>
  <el-table :data="tableData" style="width: 100%" v-loading = "loading" height="calc(100vh - 202px)">
    <el-table-column label prop="isDir" width="60" align="center">
      <template slot-scope="scope">
        <img :src="setFileImg(scope.row)" style="width: 30px" />
      </template>
    </el-table-column>
    <el-table-column prop="fileName" label="文件名">
      <template slot-scope="scope">
        <div style="cursor: pointer" @click="handleFileNameClick(scope.row)">
          {{
            scope.row.extendName
                ? `${scope.row.fileName}.${scope.row.extendName}`
                : `${scope.row.fileName}`
          }}
        </div>
      </template>
    </el-table-column>
    <el-table-column prop="extendName" label="类型" width="100">
      <template slot-scope="scope">
        <span>{{scope.row.extendName ? scope.row.extendName : '文件夹'}}</span>
      </template>
    </el-table-column>
    <el-table-column prop="fileSize" label="大小" width="60">
      <template slot-scope="scope">
          <span>{{calculateFileSize(scope.row.fileSize)}}</span>
      </template>
    </el-table-column>
    <el-table-column prop="uploadTime" label="修改日期" width="180">
    </el-table-column>
    <el-table-column label="操作" width="220">
      <template slot-scope="scope">
        <!-- 操作列展开状态下的按钮 -->
        <el-dropdown trigger="click">
          <el-button size="mini">
            操作
            <i class="el-icon-arrow-down el-icon--right"></i>
          </el-button>
          <el-dropdown-menu slot="dropdown">
            <el-dropdown-item @click.native="handleClickDelete(scope.row)"
            >删除</el-dropdown-item
            >
            <el-dropdown-item @click.native="handleClickMove(scope.row)"
            >移动</el-dropdown-item
            >
            <el-dropdown-item @click.native="handleClickRename(scope.row)"
            >重命名</el-dropdown-item
            >
            <el-dropdown-item v-if = "scope.row.isDir === 0">
              <a :href="`http://localhost:8088/filetransfer/downloadfile?userFileId=${scope.row.userFileId}`" target="_blank" style="display: block; color: inherit">下载</a>
            </el-dropdown-item>
          </el-dropdown-menu>
        </el-dropdown>
      </template>
    </el-table-column>
  </el-table>
</template>

<script>

import { deleteFile } from '@/request/file.js' //  引入接口
export default {
  name: "FileTable",
  props: {
    // 表格数据，同时需要删除原本在 data( return { } ) 中的 tableData，否则会报错
    tableData: {
      type: Array,
      required: true
    },
    // 表格加载状态
    loading: {
      type: Boolean,
      required: true
    }
  },
  data() {
    return {
      fileImgMap: {
        apk: require('@/assets/images/apk.png'),
        csv: require('@/assets/images/csv.png'),
        doc: require('@/assets/images/doc.png'),
        excel: require('@/assets/images/excel.png'),
        exe: require('@/assets/images/exe.png'),
        fold: require('@/assets/images/fold.png'),
        gif: require('@/assets/images/gif.png'),
        html: require('@/assets/images/html.png'),
        json: require('@/assets/images/json.png'),
        mp3: require('@/assets/images/mp3.png'),
        mp4: require('@/assets/images/mp4.png'),
        other: require('@/assets/images/other.png'),
        pdf: require('@/assets/images/pdf.png'),
        ppt: require('@/assets/images/ppt.png'),
        rar: require('@/assets/images/rar.png'),
        svg: require('@/assets/images/svg.png'),
        txt: require('@/assets/images/txt.png'),
        zip: require('@/assets/images/zip.png')
      }
    };
  },
  methods: {

    // 删除按钮 - 点击事件
    // 删除按钮 - 点击事件
    handleClickDelete(row) {
      console.log("row", row);
      // 消息弹框提示用户
      this.$confirm('此操作将永久删除该文件, 是否继续?', '提示', {
        confirmButtonText: '确定',
        cancelButtonText: '取消',
        type: 'warning'
      })
          .then(() => {
            // 确定按钮 点击事件 调用删除文件接口
            deleteFile(row).then((res) => {
              if (res.success) {
                this.$emit('getTableData') //  刷新文件列表
                this.$message.success('删除成功')
              } else {
                this.$message.error(res.message)
              }
            })
          })
          .catch(() => {
            //  取消
            this.$message({
              type: 'info',
              message: '已取消删除'
            })
          })
    },
    //  根据文件扩展名设置文件图片
    setFileImg(row) {
      if (!row.extendName) {
        //  文件夹
        return this.fileImgMap.fold
      } else if (['jpg', 'png', 'jpeg'].includes(row.extendName)) {
        // 图片类型，直接显示缩略图
        return this.downloadImgMin(row)
      } else {
        const fileTypeMap = {
          pptx: 'ppt',
          doc: 'word',
          docx: 'doc',
          xls: 'excel',
          xlsx: 'excel'
        }
        //  可以识别文件类型的文件
        return this.fileImgMap[row.extendName] || this.fileImgMap[fileTypeMap[row.extendName]] || this.fileImgMap.other
      }
    },
    // 移动按钮 - 点击事件
    handleClickMove(row) {
      console.log("移动", row.fileName);
    },
    // 重命名按钮 - 点击事件
    handleClickRename(row) {
      console.log("重命名", row.fileName);
    },
    //calc file size
    calculateFileSize(size) {
        const B = 1024
        const KB = Math.pow(1024, 2)
        const MB = Math.pow(1024, 3)
        const GB = Math.pow(1024, 4)
        if (!size) {
            return '_'
        } else if (size < KB) {
            return (size / B).toFixed(0) + 'KB'
        } else if (size < MB) {
            return (size / KB).toFixed(1) + 'MB'
        } else if (size < GB) {
            return (size / MB).toFixed(2) + 'GB'
        } else {
            return (size / GB).toFixed(3) + 'TB'
        }
    },
    /**
     * 文件名点击事件
     * @param {行数据} row 
     */
    handleFileNameClick(row){
      //  若是目录则进入目录
      if (row.isDir) {
            this.$router.push({
                query: {
                    filePath: `${row.filePath}${row.fileName}/`,
                    fileType: 0
                }
            })
        }
    }
  }
};
</script>
